const Schedule = require('./Schedule')

const scheduleData = new Schedule("; path=/; HttpOnly; SameSite=Lax");
async function Find(year,month,day) {
 
 let data = await scheduleData.ShowDataFind(year,month,day);
 console.log(`${data.name}\n`)
 console.log(`Lịch học ${day}/${month}/${year}`)
 if(data.data.length==0){
    console.log(`Khum có lịch học :v`);
 }else{
    for(item of data.data){
        console.log(`+${item.name}:${item.details.tietHoc}\n`)
    }
 }

}

Find(2022,2,15);